        this.addCustomer(CommonCustomers.MAGICIAN, "Magician", "魔法使");
        this.addCustomer(CommonCustomers.FOREST_FAIRY, "Forest Fairy", "森之妖精");
        this.addCustomer(CommonCustomers.LOST_DOLL, "Lost Doll", "迷之人形");
        this.addCustomer(CommonCustomers.TSUCHIGUMO, "Tsuchigumo", "土蜘蛛");
        this.addCustomer(CommonCustomers.ONI, "Oni", "鬼");
        this.addCustomer(CommonCustomers.HONE_ONNA, "Hone-onna", "骨女");
        this.addCustomer(CommonCustomers.HELL_RAVEN, "Hell Raven", "地狱鸦");
        this.addCustomer(CommonCustomers.UBUME, "Ubume", "姑获鸟");
        this.addCustomer(CommonCustomers.YOUKAI_LEOPARD, "Youkai Leopard", "豹女");
        this.addCustomer(CommonCustomers.MONK, "Monk", "僧侣");
        this.addCustomer(CommonCustomers.YOUKAI_MOUSE, "Youkai Mouse", "妖怪鼠");
        this.addCustomer(CommonCustomers.HACHISHAKU_SAMA, "Hachishaku-sama", "八尺大人");
        this.addCustomer(CommonCustomers.TAOIST, "Taoist", "道士");
        this.addCustomer(CommonCustomers.JIANGSHI, "Jiangshi", "僵尸");
        this.addCustomer(CommonCustomers.HERMIT, "Hermit", "仙人");
        this.addCustomer(CommonCustomers.INCHLING, "Inchling", "小人族");
        this.addCustomer(CommonCustomers.DELINQUENT_BOY, "Delinquent Boy", "不良少年");
        this.addCustomer(CommonCustomers.DELINQUENT_GIRL, "Delinquent Girl", "不良少女");
        this.addCustomer(CommonCustomers.TOY_SOLDIER, "Toy Soldier", "玩具兵");
        this.addCustomer(CommonCustomers.CONVALLA_FAIRY, "Convalla Fairy", "铃兰花精");
        this.addCustomer(CommonCustomers.SUNFLOWER_FAIRY, "Sunflower Fairy", "太阳花精");
        this.addCustomer(CommonCustomers.ROSE_FAIRY, "Rose Fairy", "玫瑰花精");
        this.addCustomer(CommonCustomers.KAGE_ONNA, "Kage-onna", "影女");
        this.addCustomer(CommonCustomers.POKER_SOLDIER, "Poker Soldier", "纸牌兵");
        this.addCustomer(CommonCustomers.CLOWN, "Clown", "小丑");
        this.addCustomer(CommonCustomers.MAD_CAP, "Mad Cap", "疯帽匠");
        this.addCustomer(CommonCustomers.LUNARIAN, "Lunarian", "月人");
        this.addCustomer(CommonCustomers.MEDICINE_POUNDING_RABBIT, "Medicine-Pounding Rabbit", "捣药兔");
        this.addCustomer(CommonCustomers.LUNAR_EMISSARY, "Lunar Emissary", "月之使者");


        this.addCustomerDescription(CommonCustomers.YOUKAI_RABBIT, "", "兔子就算变成了妖怪，也还是喜欢甘甜新鲜的味道呢，真是可爱。当然啦，已经成为了妖怪，不吃肉是不可能的。吃肉的样子也很可爱。");
        this.addCustomerDescription(CommonCustomers.YOUKAI_CAT, "", "妖怪猫特征是两尾分岔成两股，据说妖力越大，分岔越明显。明明长得那么可爱，性格却很凶！幻想乡就连野猫的嘴巴也很刁呢。");
        this.addCustomerDescription(CommonCustomers.YOUKAI_TANUKI, "", "性格暴躁，总是摆出一副老油条的样子，其实也没啥本事吧。不过，它们似乎很擅长变幻，要警惕它们用叶子来付账！");
        this.addCustomerDescription(CommonCustomers.YOUKAI_FOX, "", "经常用一副过来人的口气说话，有种倚老卖老的感觉。不过，可能是因为活得比较久，有时候也会说一些似乎挺有用的话。");
        this.addCustomerDescription(CommonCustomers.YOUKAI_SNAKE, "", "似乎是上古的凶兽…曾经是这样认为的。实际见了之后，才发现只是一只馋怪而已。食量很大，而且对口感的要求很高。");
        this.addCustomerDescription(CommonCustomers.HUMAN_CHILD, "", "吵吵闹闹的人类小不点儿，这种家伙要是在以前…现在好好接触下来以后，偶尔看着他们亲近自己的笑脸，会不知不觉地感到疲劳减少，真是奇怪啊。");
        this.addCustomerDescription(CommonCustomers.HUMAN_MALE, "", "看着也不是多了不起的角色，却总是自说自话。尤其是喝了酒就喜欢发牢骚。不过在人类这一种族中，似乎是体格最强的存在，常被依赖着。");
        this.addCustomerDescription(CommonCustomers.HUMAN_FEMALE, "", "只要聚在一起就会有说不完的话，基本说的都是些生活琐事，或者互相奉承衣服首饰什么的。偶尔还能听到关于料理的技巧，这点倒是挺好的。");
        this.addCustomerDescription(CommonCustomers.HUMAN_ELDER, "", "人类的长者充其量也不过活了几十年罢了，对我们妖怪来说是很短的岁月。但是有些老人身上似乎有种仙人般的气质…偶尔听听老人的话，应该也不会吃亏吧。");
        this.addCustomerDescription(CommonCustomers.SAEMON, "", "据说是人类里的有名的大胃王，为了追寻美味，甚至不惜离开村子到处旅行…能平安地活着真是不容易啊，就让我来满足你的胃吧。");
        this.addCustomerDescription(CommonCustomers.ZASHIKI_WARASHI, "", "一直以为座敷童子是地缚灵的一种，没想到这种认知是错误的。似乎只要依附在什么东西上，就可以到处往来的样子。对了，听说座敷童子会给店家带来好运，至少希望这个传言是真的呢。");
        this.addCustomerDescription(CommonCustomers.KAPPA, "", "传说中的河童只是擅于弄水，幻想乡里的河童却还擅于经商，可以说是我的大前辈。那份游刃有余地拨着算盘的身姿，偶尔会让我移不开眼睛呢。");
        this.addCustomerDescription(CommonCustomers.GOBLIN, "", "让人有点儿头疼的客人。虽然性格挺沉稳的，但似乎因为长相，会吓到一些人类客人。真是搞不懂，明明和其他妖怪同桌都没问题啊…");
        this.addCustomerDescription(CommonCustomers.TENGU, "", "谈吐虽然彬彬有礼，却又感觉有点儿强势。这是时常跑外勤的鸦天狗这一类天狗的通性，我实在有些不擅于应付。不过来者是客，我会努力照顾好的！");
        this.addCustomerDescription(CommonCustomers.FAIRY, "", "妖精其实不用吃东西，它们看见人吃美味的东西就模仿着吃。喜欢热闹，也喜欢恶作剧，千万要注意别着了它们的道！");
        this.addCustomerDescription(CommonCustomers.WHITE_WOLF_TENGU, "", "天狗的社会有严密的等级制度，山中侍卫这一职务基本都是由白狼天狗担当。大概是职责所在，他们多数的性格比较严肃，但有时候喝多了也会口无遮拦。");
        this.addCustomerDescription(CommonCustomers.YAMANBA, "", "住在妖怪山上的非常孤僻的种族，哪怕是同族之间也几乎没有交流。有传言说她们会抓走在山中迷路的小孩…但这是误会，虽然她们经常撂狠话，可她们只是不善言谈，其实是非常直爽善良的妖怪。");
        this.addCustomerDescription(CommonCustomers.YAMAWARO, "", "舍弃了河的河童，跑到妖怪之山的深处建立了大本营，依然是山上的专家！在经济方面的研究尤其先进，构筑着复杂的金钱系统，是我完全无法理解的领域。");
        this.addCustomerDescription(CommonCustomers.MAGICIAN, "", "魔法森林里生长着许多有助于魔法使提高魔力的蘑菇，因此这里住着好多魔法使。她们大多独居，性格比较孤僻，大概魔法修行本身就是一件寂寞的事情吧。");
        this.addCustomerDescription(CommonCustomers.FOREST_FAIRY, "", "妖精越多，大自然就会越有生机。魔法森林的各种物资都非常丰富，这是因为森林中寄宿许多妖精。据说每棵树都有妖精寄宿其中。妖精多恶作剧也多，要小心才行呢。");
        this.addCustomerDescription(CommonCustomers.LOST_DOLL, "", "来历不明的人偶。暂时还不确定是不是付丧神。毕竟森林里住着一位能够操纵人偶的魔法使…但这些人偶看起来实在不像是被操纵的，大概还是付丧神吧？");
        this.addCustomerDescription(CommonCustomers.TSUCHIGUMO, "", "潜伏在黑暗风穴内的土蜘蛛。虽然大多数性格让人难以理解，但对待建筑事业的态度十分认真虔诚，同伴之间也会经常探讨建筑学的问题。值得我学习呢。");
        this.addCustomerDescription(CommonCustomers.ONI, "", "远古时期就已经存在、传说中幻想乡最强的妖怪种族！但其实已经离开幻想乡很久了，没想到原来是盘踞在地底世界。鬼族性格爽朗但凶猛，绝对不能对他们说谎哦！");
        this.addCustomerDescription(CommonCustomers.HONE_ONNA, "", "非常擅长打扮的姐姐们，谈吐温柔又成熟。手上总是执着一盏牡丹花灯，据说可以迷惑过路的人类。实际上在洞穴遇到时，会帮我照亮前面的路。");
        this.addCustomerDescription(CommonCustomers.HELL_RAVEN, "", "栖息于旧地狱最深处的地狱鸦。住在旧地狱的妖怪基本上都是因为原住地成了废墟，继而迁居于此，但地狱鸦本来就住在地狱，是这里最早的住民。");
        this.addCustomerDescription(CommonCustomers.UBUME, "", "传说中穿上羽毛就是鸟，脱下羽毛就会变成少女的妖怪。通过收集别人的指甲可以预知福祸，所以从事占卜业的很多。大概是为了保持神秘，说话总是神神叨叨的。");
        this.addCustomerDescription(CommonCustomers.YOUKAI_LEOPARD, "", "野性十足的妖兽。性格爽朗而任性。出于种族天性，我有点儿害怕她们…不过，虽然豹子本身的实力很强大，但能成为妖怪的数量似乎并不多。");
        this.addCustomerDescription(CommonCustomers.MONK, "", "人类可能不太了解，但我知道…命莲寺的修行僧几乎都是妖怪。虽说也会进行什么六个菠萝蜜的修行，但谁也没看出究竟有什么效果，不少妖怪在修行之外依然我行我素。");
        this.addCustomerDescription(CommonCustomers.YOUKAI_MOUSE, "", "幻想乡随处可见的探宝者。要是能和它们打好关系，以后就不用担心丢东西了。不过委托它们寻找食物的话，可能会在拿回来之前就被它们啃光。");
        this.addCustomerDescription(CommonCustomers.HACHISHAKU_SAMA, "", "身长八尺的鬼怪，总是戴着一顶宽檐帽所以皮肤很白。过去还喜欢穿白色连衣裙，结果白天的时候存在感很低，几乎整个种族都饿瘦了。现在有些上进的也开始寻找其他更能增加注视的服饰了。");
        this.addCustomerDescription(CommonCustomers.TAOIST, "", "在神灵庙里有不少拜神子为师，希望学习仙术的弟子。不过似乎只被支使用来打杂。看起来总是一副斗志昂扬、雄心勃勃的样子…说不定打杂也是一个很有趣的工作？");
        this.addCustomerDescription(CommonCustomers.JIANGSHI, "", "受邪仙操纵的僵尸。虽然是尸体但是不会腐烂，拥有比生前更强劲的力量。脑子不太好使，想与之沟通也很困难，但胜在不挑食。据说人类要是被咬到会暂时变成它们的同类，感觉还挺有趣的。就像“僵尸体验卡”？");
        this.addCustomerDescription(CommonCustomers.HERMIT, "", "通过长年累月的修行获得超越常人能力的人类，对很多妖怪来说是上等佳肴，活得可谓是多灾多厄了。大概是因为活得太艰难，所以他们的性格都有些古怪…");
        this.addCustomerDescription(CommonCustomers.INCHLING, "", "传说中是少彦名神的后裔一族，身长只有一寸左右。因为一直在城里没有出去过，所以普遍缺乏常识，但拥有很强的求知心，对外界十分向往。");
        this.addCustomerDescription(CommonCustomers.DELINQUENT_BOY, "", "正邪从幻想乡四处蛊惑来的各种族男性，几乎都是对未来感到迷茫的年轻人，对于正邪提出的“宏图伟业”感到热血沸腾而追随于她。但似乎现在更加迷茫了…");
        this.addCustomerDescription(CommonCustomers.DELINQUENT_GIRL, "", "正邪从幻想乡四处蛊惑来的各种族女性，几乎都是对未来感到迷茫的年轻人，对于正邪提出的“宏图伟业”感到热血沸腾而追随于她。但似乎现在更加迷茫了…");
        this.addCustomerDescription(CommonCustomers.TOY_SOLDIER, "", "因为万宝槌的力量而活过来的道具。似乎受哪位高人指点，将体内本该被回收的小槌魔力转化成了自己的魔力，从此得到了真正的生命。");
        this.addCustomerDescription(CommonCustomers.CONVALLA_FAIRY, "", "寄宿在铃兰花中的妖精。每天都在致力于解开“梅蒂欣小姐说的铃铃究竟是谁”之谜，目前的悬赏已经高达九十九颗“史上最圆的石头”，依然没有人能解开谜题。");
        this.addCustomerDescription(CommonCustomers.SUNFLOWER_FAIRY, "", "寄宿在向日葵中的妖精。据说向日葵之所以一直向着太阳，就是因为她们偷偷躲在背后给花转向。这一招把不少人类都骗倒了，是她们引以为傲的绝技。");
        this.addCustomerDescription(CommonCustomers.ROSE_FAIRY, "", "寄宿在玫瑰花中的妖精。不知道她们从哪里听说，玫瑰是某颗星球上独一份的、最娇贵的花，于是掀起了要集体搬家的热潮。不过还没有妖精成功。");
        this.addCustomerDescription(CommonCustomers.KAGE_ONNA, "", "性质上介于幽灵和怨灵之间的灵。似乎因为离世的时候怀有怨恨，所以喜欢对人类恶作剧。夜晚在屋中看到一个人的影子来回走却找不到人，就是影女捣的鬼。模样看起来有些阴沉，其实都是装出来的。");
        this.addCustomerDescription(CommonCustomers.POKER_SOLDIER, "", "由魔界造物主的魔力所化的纸牌人。性格老实到木讷，即使没有被安排工作也会非常自觉地去巡逻。另外总在期待着有什么人从天而降的样子，似乎和什么兔子洞的故事有关？");
        this.addCustomerDescription(CommonCustomers.CLOWN, "", "由魔界造物主的魔力所化的纸牌人，担当着类似士兵长的职位。不仅没有长官的架子，连能安排给士兵们的工作也没有。整天在魔界各处游荡，比起士兵长，更像街头艺人什么的。");
        this.addCustomerDescription(CommonCustomers.MAD_CAP, "", "擅长制帽和剪裁的匠人。据说在保存制帽用的毛毡布时需要用到水银，因此他们经常发生水银中毒的抽搐现象，有时甚至会出现幻觉，所以被称为疯帽匠。但我知道，在疯癫的外衣下是对自己作品的热烈和执着。");
        this.addCustomerDescription(CommonCustomers.LUNARIAN, "", "居住在月之都的人。他们舍弃了寿命，致力于去除污秽以消除生死。但他们并非不老不死，也会因为事故和战争而死去，身上还是微微带有一丝污秽。");
        this.addCustomerDescription(CommonCustomers.MEDICINE_POUNDING_RABBIT, "", "负责捣药的月兔。看起来像是在捣年糕，但臼里的东西其实是药。捣药的行为并不是为了产出有价值的药，而是为了替某个人赎罪。因为一直重复着看起来毫无益处的劳动，积累了不少疲倦。");
        this.addCustomerDescription(CommonCustomers.LUNAR_EMISSARY, "", "负责月都警备工作的月兔。月之使者这个工作在月兔的一众工作中相对纪律比较严格。为保证在关键时刻能和地上人进行交战，它们需要接受非常严格的训练，很不轻松。");

        this.addCustomerChat(CommonCustomersChat.YOUKAI_RABBIT_CHAT_0, "", "注重健康的生活才能长寿呜撒！这就是妖怪兔的智慧呜撒！");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_RABBIT_CHAT_1, "", "一般来说遇到我们的Boss可以获得幸运呜撒！不过如果是在这里的话。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_RABBIT_CHAT_2, "", "竹林很漂亮的呜撒！笋也很好吃呜撒！但是外人不许进去呜撒！");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_RABBIT_CHAT_3, "", "满月的时候，会有人变得奇怪呜撒…和我们可没关系哦！");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_RABBIT_CHAT_4, "", "乌冬？听起来很有亲切感呜撒！会很好吃吧！");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_CAT_CHAT_0, "", "希望这家店的食材可以新鲜一点，猫的嘴可是很刁的。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_CAT_CHAT_1, "", "晚上有这么大的红灯笼的店铺，乍一看还挺吓人的呢。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_CAT_CHAT_2, "", "说猫有九条命的人，绝对是和猫有仇吧！");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_CAT_CHAT_3, "", "听说妖兽尾巴越多则越强，但一般妖怪猫都只有两条尾巴。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_CAT_CHAT_4, "", "沾到水的感觉很讨厌啊，下雨天就只想在家里睡觉。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_TANUKI_CHAT_0, "", "今天遇到的那个神社的巫女真的好可怕啊。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_TANUKI_CHAT_1, "", "别一直盯着我呀，酒都不好喝了。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_TANUKI_CHAT_2, "", "知道啦！我不会拿叶子来付款的啦！");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_TANUKI_CHAT_3, "", "老大最近又得到了很多付丧神，这下我们的力量就更强大了！");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_TANUKI_CHAT_4, "", "月亮很漂亮吧？可是你看到的，是真正的月亮吗？");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_FOX_CHAT_0, "", "我倒要看看现在的年轻人的居酒屋搞得怎么样。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_FOX_CHAT_1, "", "对长者放尊重点，我掉过的P点比你吃过的米还多。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_FOX_CHAT_2, "", "酒这东西，年轻人都喜欢兑水喝…不行，不行。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_FOX_CHAT_3, "", "如果加入某些高级的食材，料理的氛围也会变得高级！给我好好记住啊！");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_FOX_CHAT_4, "", "要多读书多看报…就算天狗的报纸不太靠谱，但是偶尔也有稀有情报。");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_SNAKE_CHAT_0, "", "妖兽果然还是要吃肉啊！");
        this.addCustomerChat(CommonCustomersChat.YOUKAI_SNAKE_CHAT_1, "", "那里的夜雀看起来很好吃的样子…什么，是店员不是吃的啊。");
