        this.addCustomerDescriptionLevel(RareCustomers.WRIGGLE_NIGHTBUG, "1", "", "喜欢虫子的老友。虽然咱们已经认识了很久，但我还是受不了围在她身边的那群虫子。");
        this.addCustomerDescriptionLevel(RareCustomers.WRIGGLE_NIGHTBUG, "3", "", "这家伙表面上是个萤火虫妖怪，其实是强大的上古虫族的末裔哦，所以才总摆出一副了不起的样子。");
        this.addCustomerDescriptionLevel(RareCustomers.WRIGGLE_NIGHTBUG, "5", "", "我很了解她，虽然看起来脾气不太好，但其实是很为朋友着想的家伙！谁能想到，就是这么个小小的萤火虫，希冀着用自己的微末光芒，孤独又决然地照亮这衰败已久的一族呢？");
        this.addCustomerDescriptionLevel(RareCustomers.RUMIA, "1", "", "喜欢黑暗的老友，总觉得她脑子空空的样子。但不得不说，和我很合得来。无论是第一点还是第二点。");
        this.addCustomerDescriptionLevel(RareCustomers.RUMIA, "3", "", "这家伙总是到处漂荡，我从来都不知道她在做什么。一段时间没见，就能从她口中听到些新鲜的词汇…她到底是去哪了呢？");
        this.addCustomerDescriptionLevel(RareCustomers.RUMIA, "5", "", "相识越久，越觉得自己对她的过去一无所知，就算问她，她也只会说不记得了。不过就算如此，我们也依然是好友，永远都会是好友。");
        this.addCustomerDescriptionLevel(RareCustomers.CHEN, "1", "", "与其说是凶兆的黑猫，不如说是凶巴巴的黑猫…");
        this.addCustomerDescriptionLevel(RareCustomers.CHEN, "3", "", "老是脱口而出要监视我们什么的，就那么怕我们赖账吗？明明一直都很准时还债的啊！");
        this.addCustomerDescriptionLevel(RareCustomers.CHEN, "5", "", "我说，这家伙果然有什么不可告人的目的吧？总觉得她在拙劣地隐瞒着什么…不过这孩子性格这么直，我能感受到她对我是没有恶意的！所以，不管她是不是真的隐瞒了什么，我都会对她一如既往的。");
        this.addCustomerDescriptionLevel(RareCustomers.HIEDA_NO_AKYUU, "1", "", "人类村子中的名门望族，编撰《幻想乡缘起》的稗田家家主，是个了不起的大小姐。");
        this.addCustomerDescriptionLevel(RareCustomers.HIEDA_NO_AKYUU, "3", "", "明明是才华横溢的大小姐，但是身体却很糟糕。即便拖着这样的身体，她也偶尔会来店里做客，真是让人又惊喜又担忧啊。");
        this.addCustomerDescriptionLevel(RareCustomers.HIEDA_NO_AKYUU, "5", "", "虽然这位大小姐看起来是无可挑剔的优雅，但骨子里似乎透着一股倔强和任性呢。轮回转生吗…就算这样，现在的她，也确实是一个小孩子没错吧？");
        this.addCustomerDescriptionLevel(RareCustomers.KEINE_KAMISHIRASAWA, "1", "", "在人类村子开私塾的妖怪。哎呀，总觉得她与其说是妖怪，倒不如说更像是人类呢。");
        this.addCustomerDescriptionLevel(RareCustomers.KEINE_KAMISHIRASAWA, "3", "", "明明是妖怪，却深受人类的信赖，收集了不少信仰心吧？在村民们的心中，她比巫女更可靠。听说还在村子里代理着巫女的工作。");
        this.addCustomerDescriptionLevel(RareCustomers.KEINE_KAMISHIRASAWA, "5", "", "一边担忧着人类，一边担忧着妖怪，真是伟大啊，所谓贤者就是指这样的存在吧？她似乎有着另一个形态，一个我应该没有见过的形态，但却又隐约觉得自己见过…");
        this.addCustomerDescriptionLevel(RareCustomers.KASEN_IBARAKI, "1", "", "一本正经的谜之仙人。总觉得她和一般的仙人哪里不太一样…不过我也没见过别的仙人就是了。");
        this.addCustomerDescriptionLevel(RareCustomers.KASEN_IBARAKI, "3", "", "仙人说话都是这样一板一眼吗？和她对话有种挨训的感觉…不过能让主食霞的仙人来自己的店里光顾，还是挺有成就感的。");
        this.addCustomerDescriptionLevel(RareCustomers.KASEN_IBARAKI, "5", "", "虽然有点儿啰嗦，但真是个热心的家伙，是不是有点儿像（有点儿严厉的）邻家姐姐的感觉呢？气质和一开始相比变了不少，该说是更柔和了吗？");
        this.addCustomerDescriptionLevel(RareCustomers.HAKUREI_REIMU, "1", "", "贫穷且凶狠的巫女小姐…让人怀疑她真的是人类吗？总之，千万要小心不要惹她生气。");
        this.addCustomerDescriptionLevel(RareCustomers.HAKUREI_REIMU, "3", "", "灵梦小姐真是一点儿都不客气啊…不过，不知不觉也受了她不少照顾呢。开始有点儿明白为什么有那么多妖怪聚集在她身边了。");
        this.addCustomerDescriptionLevel(RareCustomers.HAKUREI_REIMU, "5", "", "所谓刀子嘴豆腐心，说的就是灵梦小姐这样的人吧。虽然看起来挺没心没肺的，但那双眼睛却总是能直视前方。博丽的巫女是灵梦小姐真是太好了。");
        this.addCustomerDescriptionLevel(RareCustomers.IBUKI_SUIKA, "1", "", "没想到现在的幻想乡居然还有鬼存在，第一次见到的时候真的吓了一跳！不过…她真的是鬼吗？");
        this.addCustomerDescriptionLevel(RareCustomers.IBUKI_SUIKA, "3", "", "毫无疑问，她就是鬼。虽然平时摆着一副小小的身姿和迷迷糊糊的模样，但言语间的气魄，有时会瞬间像一座山一样压下来。真不愧是传说中的山中王者啊。");
        this.addCustomerDescriptionLevel(RareCustomers.IBUKI_SUIKA, "5", "", "鬼虽然是很可怕的种族，但是一旦成为朋友，就是最值得信赖的伙伴！萃香小姐虽然总是醉醺醺的，但是心思清明着呢。那种豪情逸致，真让人向往啊。");
        this.addCustomerDescriptionLevel(RareCustomers.HINANAWI_TENSHI, "1", "", "传说中气焰嚣张、目中无人的不良天人，如果可以的话，真不想招待这样的客人啊…");
        this.addCustomerDescriptionLevel(RareCustomers.HINANAWI_TENSHI, "3", "", "我得为之前说过的话道歉，怎么能对客人生出不想招待的念头呢？就算她气焰嚣张、目中无人、口无遮拦、毫无常识、鼻子比天高，我都必须要好好招待她！尽量吧…");
        this.addCustomerDescriptionLevel(RareCustomers.HINANAWI_TENSHI, "5", "", "其实，这家伙也不是那么讨厌啦。虽然嘴巴是坏了点儿（是很坏），但说不定…是个相当天真的家伙呢。似乎在天界过得不是很舒心，如果在地上能让她好好释放压力就好了。");
        this.addCustomerDescriptionLevel(RareCustomers.MARISA_KIRISAME, "1", "", "非常开朗健谈的人类魔法使，独自住在人烟罕至的魔法森林里修行，不管是人类、妖精还是妖怪都能轻松与之打成一片。对蘑菇似乎有很深刻的研究！");
        this.addCustomerDescriptionLevel(RareCustomers.MARISA_KIRISAME, "3", "", "虽然看起来无所事事，其实也经营着一家“雾雨魔法店”。因为她喜欢收集却从不整理的性格，这家店常常被误以为是垃圾回收站。客人可想而知也是没有的。");
        this.addCustomerDescriptionLevel(RareCustomers.MARISA_KIRISAME, "5", "", "虽然性格上有着心术不良的地方，但本性正直，和她一起的感觉很愉快！她从不愿让人看到她努力的样子，但我们都知道…这个自小就离家修行的小女孩，如果可以更多地依靠别人就好了。");
        this.addCustomerDescriptionLevel(RareCustomers.HONG_MEILING, "1", "", "没想到给恶魔之家的看门的妖怪居然是个热血亲切的大姐！可惜爱睡觉，每次想去找她聊聊都看到她在打盹。");
        this.addCustomerDescriptionLevel(RareCustomers.HONG_MEILING, "3", "", "美铃小姐独自守卫着这么大的洋馆，连个轮班的都没有，难怪会睡眠不足啦。要是在我力所能及的范围内，能帮到她一点点忙就好了。");
        this.addCustomerDescriptionLevel(RareCustomers.HONG_MEILING, "5", "", "原来美铃小姐的家乡在海的另一边。但是幻想乡是没有海的，美铃小姐是不是已经回不去了？她的家乡有很多耳熟能详的名菜，我努力学习做给她吃，或许可以缓解一些她的思乡之情。");
        this.addCustomerDescriptionLevel(RareCustomers.CIRNO, "1", "", "自称最强的、长着冰之羽翼的妖精，那样的翅膀也能飞起来真是神奇啊。当然神奇的还有她的脑回路，老是做一些和大家相反的选择，总之别太深究她说的话就好了。");
        this.addCustomerDescriptionLevel(RareCustomers.CIRNO, "3", "", "虽然是冰之妖精，却是个热血的家伙！说不定她真的是最强的妖精，尤其是那股勇往直前的气势，真是见了棺材也不掉泪，撞了南墙也不回头。了不起了不起！");
        this.addCustomerDescriptionLevel(RareCustomers.CIRNO, "5", "", "我发现，和她在一起的时候，会不知不觉就被她的气势带走，这就是领袖的气质吗？！不过这种感觉很轻松，说不定我们很合拍呢！难道说我也是笨蛋吗？哈哈开玩笑啦。");
        this.addCustomerDescriptionLevel(RareCustomers.PATCHOULI_KNOWLEDGE, "1", "", "总是穿着睡衣躲在树荫下的奇怪的魔法使。似乎不在意别人的眼光，对潮流什么的也不感兴趣。虽然头脑很好，不过看起来弱不禁风的样子。比起头脑好，身体好更重要啊。");
        this.addCustomerDescriptionLevel(RareCustomers.PATCHOULI_KNOWLEDGE, "3", "", "帕秋莉小姐总是手不离书，一直盯着书本看眼睛不会累吗？而且书上说的也不一定都是对的啊，像这样光读书不出门，就算知识渊博，常识却稍微有些不足呢。");
        this.addCustomerDescriptionLevel(RareCustomers.PATCHOULI_KNOWLEDGE, "5", "", "师傅原来身患贫血症和哮喘症，真是让人担心啊（我只在这里叫一下应该可以吧？）。虽然认识这么久，师傅对我的态度依然不太亲切，但却教了我不少知识，我可不能辜负她。");
        this.addCustomerDescriptionLevel(RareCustomers.FUJIWARA_NO_MOKOU, "1", "", "隐居在竹林里的不可思议的人类，欲望极低，对世间追逐的一切都没有兴趣。因为曾经吃了什么奇怪的东西而成为不老不死之身（不能乱吃东西啊）。");
        this.addCustomerDescriptionLevel(RareCustomers.FUJIWARA_NO_MOKOU, "3", "", "妹红小姐真是帅气啊，虽然是人类，却强到没边，性格也很豪迈。据说爱吃辣的人性格都很爽快，妹红小姐可是无辣不欢呢。");
        this.addCustomerDescriptionLevel(RareCustomers.FUJIWARA_NO_MOKOU, "5", "", "她比我想象中的要心思细腻，过去似乎经历了很多难以想象的苦难。即便如此，她仍然心存良善，一直暗中帮助别人。这样的她，一定会获得幸福的！");
        this.addCustomerDescriptionLevel(RareCustomers.KAGUYA_HOURAISAN, "1", "", "住在永远亭的公主殿下，据说来自月亮。放着好好的月之公主不做，跑到幻想乡来当家里蹲到底是为什么呢？");
        this.addCustomerDescriptionLevel(RareCustomers.KAGUYA_HOURAISAN, "3", "", "外表看起来是气质优雅的公主殿下，实际行事却有些无赖…有点儿理解为什么她能成为那只黑兔子的主人了（黑形容的是心哦）…");
        this.addCustomerDescriptionLevel(RareCustomers.KAGUYA_HOURAISAN, "5", "", "原来高贵的公主也会和普通人一样烦恼工作的事情。辉夜小姐和我也没什么不同嘛。作为工作了数载的前辈，我得好好为迷惘的后辈打气呢！");
        this.addCustomerDescriptionLevel(RareCustomers.TEWI_INABA, "1", "", "突然出现在店里的妖怪兔，总是坏笑着来找茬，只要她的耳朵出现在视线范围里，我的PTSD就犯了。");
        this.addCustomerDescriptionLevel(RareCustomers.TEWI_INABA, "3", "", "虽然总是高价强卖我东西，而且还狡猾的打包卖什么的…但有些东西的确对我来说很有用…");
        this.addCustomerDescriptionLevel(RareCustomers.TEWI_INABA, "5", "", "一直让灵梦小姐退治她也挺可怜的…总之要是经济宽裕的话，让她来店里也不是坏事，听说能看到她的话，就能获得一般人想象不到的幸运？");
        this.addCustomerDescriptionLevel(RareCustomers.NITORI_KAWASHIRO, "1", "", "如果说河童都是些唯利是图的商人，作为小头目的她更是其中的佼佼者！虽然说商人趋利也没什么好指责的，但是再多一点儿人情味不是也挺好吗？");
        this.addCustomerDescriptionLevel(RareCustomers.NITORI_KAWASHIRO, "3", "", "荷取小姐的头脑真是相当好啊，堪称是商业和技术的天才！一直以为河童性本趋利，可是她们却愿意在技术上一掷千金，我真是搞不懂她们了…");
        this.addCustomerDescriptionLevel(RareCustomers.NITORI_KAWASHIRO, "5", "", "能够抓住一切机会、将危机转化为商机的能力，真是让我叹为观止。在她身上学到的一切，值得我用一辈子去消化！");
        this.addCustomerDescriptionLevel(RareCustomers.MOMIJI_INUBASHIRI, "1", "", "常常在妖怪山上巡逻的白狼天狗，嗅觉、听觉非常灵敏，被称为山上的千里眼，能迅速发现入侵者。正因为有这样的守卫在，我们这种小妖怪平时根本不敢上山。");
        this.addCustomerDescriptionLevel(RareCustomers.MOMIJI_INUBASHIRI, "3", "", "因为妖怪之山基本没什么侵入者，所以守卫的工作非常清闲。夜雀食堂开张以后，她对于工作之余多了个去处似乎非常高兴，面上虽然没怎么显露，但尾巴暴露了心情。");
        this.addCustomerDescriptionLevel(RareCustomers.MOMIJI_INUBASHIRI, "5", "", "性格原本也算是一板一眼的，熟悉以后经常能听到她那些毫无城府的牢骚，还时不时能看到她露出乖巧、呆萌的一面。比想象中的好应付啊…早知道这样，我就早点儿到山上来了！");
        this.addCustomerDescriptionLevel(RareCustomers.SANAE_KOCHIYA, "1", "", "数年前与守矢神社一起突如其来的巫女。据说来自外界，和她一起来的还有两位神明…以及一座湖。这件事实在太离奇了，直到现在都感觉怪吓人的。");
        this.addCustomerDescriptionLevel(RareCustomers.SANAE_KOCHIYA, "3", "", "和喜欢宅在屋里喝茶的博丽巫女不同，早苗小姐非常勤奋，随处都能看到她在努力收集信仰的身影。以人类之身来收集信仰真是了不起啊，似乎是什么现人神呢。");
        this.addCustomerDescriptionLevel(RareCustomers.SANAE_KOCHIYA, "5", "", "博丽神社在幻想乡有着特殊的、绝对的地位，无论是守矢神社还是早苗小姐，想超越博丽之名都很艰难。不过，在早苗小姐的兢兢业业下，现在大家都记住了守矢巫女之名，真是太好了！");
        this.addCustomerDescriptionLevel(RareCustomers.ALICE, "1", "", "住在魔法森林的魔法使，有着金色的头发和白皙的皮肤，外貌精致得就像人偶一样。据说，她的家里也尽是些人偶。被她操纵的那些人偶栩栩如生，感觉还…蛮瘆人的。");
        this.addCustomerDescriptionLevel(RareCustomers.ALICE, "3", "", "这些人偶真的是被操纵的吗？无论是谁见了都会有这样的疑问。虽然她看起来对别人漠不关心，但是待人接物却都非常周到，这就是所谓的都市派吗？");
        this.addCustomerDescriptionLevel(RareCustomers.ALICE, "5", "", "想要走进她的心房真是不容易啊。她矜持而又好客，温柔而又疏离。她之所以制作这么多人偶，会不会是因为孤独呢？");
        this.addCustomerDescriptionLevel(RareCustomers.NARUMI_YATADERA, "1", "", "原本是安置在魔法之森的地藏石像，因为森林的魔力而得到了生命——森林里居然蕴藏着能够将存在本身进行变化的魔力，难怪有那么多魔法使住在这，这对修行来说也太便利了！");
        this.addCustomerDescriptionLevel(RareCustomers.NARUMI_YATADERA, "3", "", "还以为地藏像会更稳重一点儿，结果也就是刚认识的时候会摆个架子，稍微见多几次面就把话匣子全打开了嘛。是个直率的女孩呢。");
        this.addCustomerDescriptionLevel(RareCustomers.NARUMI_YATADERA, "5", "", "好不容易成为了拥有自我的生命体，结果还是个家里蹲，这不是很可惜吗？！我一定要想办法让这家伙提起干劲！");
        this.addCustomerDescriptionLevel(RareCustomers.YAMAME_KURODANI, "1", "", "在黑暗的风穴遇到的亲切的指路人。因为知道自己惹人讨厌所以几乎不会到村里去，明明那么可爱…真希望地上的大家也能认识她呢！");
        this.addCustomerDescriptionLevel(RareCustomers.YAMAME_KURODANI, "3", "", "山女小姐原来是类似地底偶像一样的存在呢！不愧是她。不过，和她那可爱的性格相对的是，她的爱好似乎异于常人…");
        this.addCustomerDescriptionLevel(RareCustomers.YAMAME_KURODANI, "5", "", "虽然一直被误会乃至成为“被厌恶者”，山女小姐也并不在意。我能感觉到，她确实深爱着这个地底世界。能有这样豁达的心境，真是了不起的境界啊。");
        this.addCustomerDescriptionLevel(RareCustomers.PARSEE_MIZUHASHI, "1", "", "原本以为她是个亲切开朗的妖怪，结果一转身就看到她在背地里说我坏话…以嫉妒为食的妖怪，不煽动别人的嫉妒心就会活不下去吗？感觉很可怜呐。不过她似乎不这么觉得。性格也阴晴不定，真是难以理解。");
        this.addCustomerDescriptionLevel(RareCustomers.PARSEE_MIZUHASHI, "3", "", "桥姬既是桥的妖怪，也是桥的守护神。帕露西小姐其实在日复一日地守望着他人平安地从地上世界和地下世界往来…这么说来，她也是个很伟大的妖怪呢。");
        this.addCustomerDescriptionLevel(RareCustomers.PARSEE_MIZUHASHI, "5", "", "我发现，帕露西小姐熟知所有人的优点！虽然大家都说帕露西小姐很善妒，但她的内心深处其实很憧憬大家吧？能够更进一步了解她真是太好了！");
        this.addCustomerDescriptionLevel(RareCustomers.YUUGI_HOSHIGUMA, "1", "", "很久以前就离开了幻想乡、有着大姐头气魄的鬼，性格刚毅且干脆利落。如今在管理着旧地狱街道上的温泉。偶尔去泡一泡温泉吧！");
        this.addCustomerDescriptionLevel(RareCustomers.YUUGI_HOSHIGUMA, "3", "", "原来勇仪小姐曾经是山中四天王之一。传闻说她有异常程度的怪力，腕力即便在鬼之中也几乎无可匹敌。没想到我也能结识到这么厉害的妖怪…果然还是有点儿紧张啊。");
        this.addCustomerDescriptionLevel(RareCustomers.YUUGI_HOSHIGUMA, "5", "", "本来以为鬼已经对人类失去兴趣…但勇仪小姐其实在偷偷羡慕着在地上自由往来的同伴的身影。既然对地上感兴趣，那就去地上玩吧！鬼就该是这样嘛！");
        this.addCustomerDescriptionLevel(RareCustomers.SATORI_KOMEIJI, "1", "", "传说中能够读心的觉妖怪，名字也是觉。大概是对自己的种族或能力很自豪吧？因为日以继夜都在工作，所以没什么搭话的机会…");
        this.addCustomerDescriptionLevel(RareCustomers.SATORI_KOMEIJI, "3", "", "觉小姐真是我见过最操劳的领主了。虽然有宠物们帮忙干杂活，但是行政方面的工作似乎只有她能做。为了工作似乎放弃了很多日常爱好，唯独不能放弃读心。累到虚脱可不好啊。");
        this.addCustomerDescriptionLevel(RareCustomers.SATORI_KOMEIJI, "5", "", "我明白为什么宠物们那么依恋觉小姐了。被繁重的工作埋没，心中还能一直牵挂着妹妹和宠物。在清冷的外表下的这份温柔，确实是会让人念念不忘呢。");
        this.addCustomerDescriptionLevel(RareCustomers.RIN_KAENBYOU, "1", "", "被称作火车的猫妖，是地灵殿之主的左右手。能够和尸体和怨灵对话似乎很方便！不过…说到火车就是偷尸体啊。就是因为这样所以被厌恶吧？唔唔，对别人的兴趣说三道四似乎不太好…");
        this.addCustomerDescriptionLevel(RareCustomers.RIN_KAENBYOU, "3", "", "仔细想想，人类刚死掉的时候，应该会茫然吧？如果能在猝然长辞之际遇到开朗善谈的阿燐，或许能中和一些对死亡的恐惧。");
        this.addCustomerDescriptionLevel(RareCustomers.RIN_KAENBYOU, "5", "", "活在偏见下的“凶兆的黑猫”，原来要经历那么艰辛的事。偏见真是不可取啊。幸好阿燐遇到了觉小姐。一个好的主人可以改变宠物的一生。希望阿燐今后可以一直过着无忧无虑地偷尸体的生活。");
        this.addCustomerDescriptionLevel(RareCustomers.UTSUHO_REIUJI, "1", "", "看守灼热地狱遗址的地狱鸦，有着火焰般热烈爽快的性格。外表看起来和其他地狱鸦不太一样，唯独脑袋空空这一点让我感到很亲切。");
        this.addCustomerDescriptionLevel(RareCustomers.UTSUHO_REIUJI, "3", "", "阿空的外表之所以大放异彩，原来是因为她的体内寄宿了神灵八咫乌！自地狱的黑暗诞生而来的地狱鸦，和栖息于太阳的八咫乌，真是奇妙的组合啊！不过…让她拥有这么强大的力量真的没问题吗？");
        this.addCustomerDescriptionLevel(RareCustomers.UTSUHO_REIUJI, "5", "", "最近突然觉得，没有比阿空更适合拥有这种力量的人选了。拥有异常强大的力量，却没有使用这种力量的头脑，这就是一种幸运吧？脑袋空空的阿空很可爱哦！不过我也常被说脑袋空空呢。");
        this.addCustomerDescriptionLevel(RareCustomers.KOGASA_TATARA, "1", "", "寄宿在怪异唐伞上的灵，因为一直没有人使用，不知不觉就付丧神化了。是个只要见到别人被吓了一跳，就会快乐得手舞足蹈的家伙。");
        this.addCustomerDescriptionLevel(RareCustomers.KOGASA_TATARA, "3", "", "这家伙的性格好麻烦啊！本来以为是个开朗亲切的妖怪，结果动不动就哭鼻子…我拿这种家伙最没办法啦！好在她总是很快就能振作起来！");
        this.addCustomerDescriptionLevel(RareCustomers.KOGASA_TATARA, "5", "", "尽管偶尔会露出悲观的一面，但她内心深处却是个爽朗坚毅的妖怪。虽然总是遭遇挫折，却总是花样层出地努力着呢。这份能量，希望我也可以拥有！");
        this.addCustomerDescriptionLevel(RareCustomers.MINAMITSU_MURASA, "1", "", "居然让醉心于让船沉没的妖怪来担任圣辇船的船长，命莲寺真是从里到外都让人无法理解。这家伙能在任何水面引发水难事故，以后得更加注意厨房积水！");
        this.addCustomerDescriptionLevel(RareCustomers.MINAMITSU_MURASA, "3", "", "虽然拜入佛门已经有千年之久，却还是一点儿佛门弟子的自觉都没有。过去在海上胡作非为惯了，至今仍瞒着住持到处恶作剧。不过对命莲寺不利的事，她是绝对不会做的。");
        this.addCustomerDescriptionLevel(RareCustomers.MINAMITSU_MURASA, "5", "", "恣性洒脱的船长，甘愿成为佛门弟子，受佛门管束（其实也不太管得住），只为报答千年前的恩情。果然不能以貌取人呀。村纱小姐她，有着一颗有情有义的金子般的心呢。");
        this.addCustomerDescriptionLevel(RareCustomers.NUE_HOUJUU, "1", "", "古老的真相不明的妖怪——鵺。长得和传说完全不一样真可惜…虽然也是命莲寺的弟子，但总是见到她独自在寺院附近无所事事地游荡，似乎不太合群的样子。");
        this.addCustomerDescriptionLevel(RareCustomers.NUE_HOUJUU, "3", "", "她就像是被忽视、通过恶作剧来吸引大家注意力的别扭的孩子。内心希望融入寺中，却笨挫地不知道该怎么表达…明明活了这么久，还是不谙世故呢。");
        this.addCustomerDescriptionLevel(RareCustomers.NUE_HOUJUU, "5", "", "越是在意就越容易畏缩…结果她的内心就和她的形象一样无法被人看清，这难道就是“无法明状之物”的寂寞吗？但她如今已经展露出自己的真相，大家以后也一定会慢慢理解她的率真的！");
        this.addCustomerDescriptionLevel(RareCustomers.MONONOBE_NO_FUTO, "1", "", "通过长时间自己诅咒自己从而沉眠的古代人。大概是睡了太久，思考方式也跟古时候一样，和普通人完全脱节…目前在努力学习现代知识，结果来说变得更加不伦不类了。");
        this.addCustomerDescriptionLevel(RareCustomers.MONONOBE_NO_FUTO, "3", "", "如果不提她那套落伍的作风，其实她也蛮有仙人那种风格，尤其对风水什么的似乎很有研究。我是搞不懂啦…要不下次装修的时候请她帮忙看看好了。");
        this.addCustomerDescriptionLevel(RareCustomers.MONONOBE_NO_FUTO, "5", "", "无法完全割舍过去，就说明对过去还留有怀念吧？尽管这样，布都小姐还是毅然决然地成为尸解仙的实验品。我虽然无法理解人类的这份忠心，但也感到非常敬佩！");
        this.addCustomerDescriptionLevel(RareCustomers.SEIGA_KAKU, "1", "", "经常见到她在神庙附近晃荡嬉玩的样子，似乎对修行不太热心…但又十分热衷于向别人传达修道的好处。实在搞不明白她到底在想什么。是个看起来很正统，行为和思想却很另类的仙人。");
        this.addCustomerDescriptionLevel(RareCustomers.SEIGA_KAKU, "3", "", "想要做成一件事就会不计后果地去达成，就算自己的行为不被人理解，她也会摆出一副理所当然的态度。要说她是被欲望驱使，又觉得恰恰相反…她所做的那些事，与其说是为了欲望，或许只是单纯的性格使然。");
        this.addCustomerDescriptionLevel(RareCustomers.SEIGA_KAKU, "5", "", "邪仙不一定就是邪恶的仙人。仅仅由于思考和行动都不够妥当就被断绝天人之路，确实是让我有些费解…我只知道青娥小姐非常有个性！如果成为天人就要泯灭个性，那我希望青娥小姐还是一直保持这个样子比较好。");
        this.addCustomerDescriptionLevel(RareCustomers.SOGA_NO_TOJIKO, "1", "", "古代人的亡灵。过去似乎怀有很深的怨恨，所以性质上是妖怪们最害怕的怨灵。有点儿不太敢接触她呢…");
        this.addCustomerDescriptionLevel(RareCustomers.SOGA_NO_TOJIKO, "3", "", "实际接触后，发现屠自古小姐的性格确实是直爽又豁达，还充满活力。一点儿也不像是怨灵呢。大概是怨恨已经消散得差不多了吧？能让心胸豁达的屠自古小姐变成怨灵，一定是相当痛苦的事情…");
        this.addCustomerDescriptionLevel(RareCustomers.SOGA_NO_TOJIKO, "5", "", "没想到没想到，让屠自古小姐变成怨灵的元凶竟然是布都小姐！可她们两人的感情还是很要好的样子？！屠自古小姐的心胸何止是豁达的程度，她大概离成佛只有一步之遥了。");
        this.addCustomerDescriptionLevel(RareCustomers.AYA_SHAMEIMARU, "1", "", "每天在幻想乡各处奔走，收集题材来写成新闻的鸦天狗。也是大名鼎鼎的《文文。新闻》的作者。之所以说大名鼎鼎，并不是这个报纸有多出色，而是派发得实在太多了…");
        this.addCustomerDescriptionLevel(RareCustomers.AYA_SHAMEIMARU, "3", "", "本来就很强的她，再加上有新闻这种强力的武器，导致文文小姐在幻想乡里经常不被待见。不过看着如此拼命工作的她，感觉也会受到鼓舞呢。如果她的新闻能少些胡扯就好了。");
        this.addCustomerDescriptionLevel(RareCustomers.AYA_SHAMEIMARU, "5", "", "报纸真的是非常伟大的东西！文文小姐创作的报刊，记录了幻想乡的过去，虽然稍微有些失真的地方…但也还是有值得回忆的地方！希望文文小姐最终能够找到适合她的新闻风格。");
        this.addCustomerDescriptionLevel(RareCustomers.MEDICINE_MELANCHOLY, "1", "", "独居在剧毒的铃兰田野的付丧神，因为才出生不久，所以经验和知识都严重地不足，也不懂得该怎么和人相处。总在偌大的铃兰田野里自言自语甚至手舞足蹈的样子，可爱中透着一些诡异…性格倒是直来直往。");
        this.addCustomerDescriptionLevel(RareCustomers.MEDICINE_MELANCHOLY, "3", "", "虽然成为了妖怪，但身体似乎还是人偶的样子。所以就算体内充盈了毒也不会感到任何不适。对人类的友好度很低，以前还会在食物里下毒来操纵人类…因为太年轻下手不懂得区分轻重，在她的心志成长起来以前，一定要特别注意！");
        this.addCustomerDescriptionLevel(RareCustomers.MEDICINE_MELANCHOLY, "5", "", "谁能想到毒人偶其实是这么单纯的孩子呢？你教给她什么，她就会吸收什么。看着新生妖怪一点点地成长起来原来是这种感觉！因为我自己也很年轻，所以很少有作为前辈的经历。现在我想为这个孩子保驾护航，让她幸福地成长…虽然我可能还没有她强。");
        this.addCustomerDescriptionLevel(RareCustomers.YUUKA_KAZAMI, "1", "", "虽然看起来是一副高雅的淑女形象，但不知道为什么，很多人将她视作“花之暴君”。虽然恐怖的传说满天飞，但大家其实都没有见过她欺负人类或者弱小妖怪。真实的她，究竟是一位怎样的人呢？");
        this.addCustomerDescriptionLevel(RareCustomers.YUUKA_KAZAMI, "3", "", "只要见过她照顾花儿的样子，那些有关她的谣言就会不攻自破。但我还是不明白，她有那么强大的妖力，为什么会容忍谣言满天飞，为什么要默默地承受那些恶意中伤呢？");
        this.addCustomerDescriptionLevel(RareCustomers.YUUKA_KAZAMI, "5", "", "大错特错！她从来都没有“忍受”过那些谣言，因为她根本就不在乎。于是连澄清都变得多此一举。幽香小姐最为强大之处，正是她的心。我想，并不是强大的妖力让她睥睨众人，真正让她立于不败之地的，是她纯粹又干净的自我。");
        this.addCustomerDescriptionLevel(RareCustomers.SEIJA_KIJIN, "1", "", "擅长花言巧语的天邪鬼。打着要颠倒幻想乡的口号，蛊惑了许多年轻气盛的妖怪甚至人类来当手下，但却因为资金不足无法善待他们，甚至找天狗刊登广告骗游客来收取过路费…无论怎么看，都是个乱来的家伙。");
        this.addCustomerDescriptionLevel(RareCustomers.SEIJA_KIJIN, "3", "", "正邪小姐真的想下克上吗？感觉她对造反成功之后的事情并没什么兴趣。或许她只是从和社会作对汲取乐趣，并不是真的想改变这个社会。");
        this.addCustomerDescriptionLevel(RareCustomers.SEIJA_KIJIN, "5", "", "看着同伴一个接一个的离开，一般人多少都会觉得此路不通吧？但是正邪小姐完全没有想过放弃。在如今人人都悠闲地过着普通日子的幻想乡中，她是少有的不达目的绝不罢休的那一类。从某种程度来说，还蛮让我敬佩的…");
        this.addCustomerDescriptionLevel(RareCustomers.SHINMYOUMARU_SUKUNA, "1", "", "非常崇拜一寸法师的小人族的城主，性格克制认真，是一个有着英雄梦的勇者厨。向往冒险的深闺公主还真是新鲜呢。擅长和菓子这一点和气质很相衬！");
        this.addCustomerDescriptionLevel(RareCustomers.SHINMYOUMARU_SUKUNA, "3", "", "明明很向往勇者的冒险，也做了非常多的准备，但是却迟迟没有踏上旅程。对于能否留下完美的传说这件事非常在意。会不会有些在意过头了…");
        this.addCustomerDescriptionLevel(RareCustomers.SHINMYOUMARU_SUKUNA, "5", "", "终于解开心结的针妙丸小姐勇敢地踏上了道路，而那些“凭着一股勇气就可以拯救世界”的故事就是她的精神道标。从她身上我也明白到，太在意结果就会寸步难行，果然还是随心而动比较适合我！");
        this.addCustomerDescriptionLevel(RareCustomers.KAGEROU_IMAIZUMI, "1", "", "稳重温婉的狼女，给人一种亲切的邻家大姐姐的感觉。不知是不是因为月人在竹林里住下的缘故，那里和月亮相关的妖怪似乎很多，影狼小姐也是其中一员。");
        this.addCustomerDescriptionLevel(RareCustomers.KAGEROU_IMAIZUMI, "3", "", "影狼小姐似乎很在意皮肤，这么爱美的狼人还真是第一次见呢。草根妖怪的日常真是平和又热闹。偶尔忍不住也会想…如果我不开店，大概也在过着这样的生活吧。");
        this.addCustomerDescriptionLevel(RareCustomers.KAGEROU_IMAIZUMI, "5", "", "影狼小姐作为狼的部分，是在外面世界已经绝种的本州狼。一度被敬仰、被崇拜，最后却落得灭绝下场真可怜。幻想乡的人类和妖怪要多多爱护我们兽（禽）类呀！");
        this.addCustomerDescriptionLevel(RareCustomers.REISEN, "1", "", "似乎因为我来自地上，所以对我很亲切的月之使者，和永远亭的铃仙小姐有着一样的名字。偶尔会表现出对地上的向往，不知道是不是过去发生了什么…也可能是因为月之使者的训练太辛苦了吧。");
        this.addCustomerDescriptionLevel(RareCustomers.REISEN, "3", "", "原来铃仙曾经是一只捣药兔，因为厌烦无休止的捣药逃到幻想乡而发生了许多事，所以才成为一名月之使者。难怪她会对地上表现出眷恋。不过她似乎也不喜欢月之使者的工作，感觉她从内到外都过得好辛苦啊…");
        this.addCustomerDescriptionLevel(RareCustomers.REISEN, "5", "", "一直活在后悔中是一种怎样的心情呢？如果时间可以重来，她就不会从捣药的工作中逃走了吗？那样她就会感到幸福吗？这些问题我都没能问出口…不过，与其徘徊在过去，还是向前看比较好吧？希望她有朝一日能得到真正的自由。");
        this.addCustomerDescriptionLevel(RareCustomers.WATATSUKI_NO_TOYOHIME, "1", "", "绵月家的姐姐。性格和蔼温柔，偶尔会露出孩子气的一面。除了偶尔会在月之使者训练时给兔子们带小点心，几乎没有参与月之使者的训练，因此很受月兔的喜爱。");
        this.addCustomerDescriptionLevel(RareCustomers.WATATSUKI_NO_TOYOHIME, "3", "", "丰姬小姐真是相当——相当喜欢桃子，以及相当——相当优哉游哉。像她这么强大的人，真的可以这样什么都不用操心吗？无论在什么环境下都能活得这么天真，这应该也算是一种能力吧？");
        this.addCustomerDescriptionLevel(RareCustomers.WATATSUKI_NO_TOYOHIME, "5", "", "原来丰姬小姐心里也有想要完成的事呢。她是从什么时候开始产生想要隐退的想法呢？或许从一开始，她就只是被迫继承月之使者首领的工作吧。至今没有隐退，一来是没有合适的继任者，二来…恐怕还是为了依姬小姐吧？");
        this.addCustomerDescriptionLevel(RareCustomers.WATATSUKI_NO_YORIHIME, "1", "", "绵月家的妹妹。个性认真严谨，担负着兔子们的战斗、学习、礼法的训练——几乎包揽了月之使者首领该做的所有活儿。虽然实际上几乎没有战斗，但对待训练却很严格，兔子们要是偷懒就会被严厉惩罚。");
        this.addCustomerDescriptionLevel(RareCustomers.WATATSUKI_NO_YORIHIME, "3", "", "因为性格太过于一板一眼，对待训练又十分严厉，兔子们都不太亲近她。和清闲自在的姐姐相反，依姬小姐似乎一直处于无法放松的状态，可能聪明人总是容易想太多…");
        this.addCustomerDescriptionLevel(RareCustomers.WATATSUKI_NO_YORIHIME, "5", "", "依姬小姐继承了师傅的意志，想要为月之都做出贡献，所以她才时刻保持着危机感。严格操练士兵，也是不希望她们在战争中死去。将所有一切背负下来的依姬小姐，真是坚强又温柔啊…");
        this.addCustomerDescriptionLevel(RareCustomers.ELLEN, "1", "", "勤劳、善良热情的小女孩，开着一家“蓬松松爱莲”魔法店，还养了一只叫做苏格拉底的、个性有点儿酷的猫。");
        this.addCustomerDescriptionLevel(RareCustomers.ELLEN, "3", "", "只要遇到需要帮助的人，爱莲小姐就会尽十二分努力去帮助，是个非常友好的魔法使！爱莲小姐对工作也一直保持着相当的热忱，每次和她对话感觉自己也变得活力满满了。");
        this.addCustomerDescriptionLevel(RareCustomers.ELLEN, "5", "", "明明外表和个性看起来都很年幼，却是个已经活了几千年的大魔法使，真是完全看不出来！活得久的妖怪我也见了不少，但活了那么久还能保持这份纯真、浪漫和善良的，爱莲小姐真是独一人！");
        this.addCustomerDescriptionLevel(RareCustomers.MIMA, "1", "", "独自在魔界进行着（危险？）研究的…学者？自称是神灵，但被大家视为恶灵或邪灵。不管怎么样，能感受到她扎扎实实的强大和自信，她到底是怎样的存在呢？");
        this.addCustomerDescriptionLevel(RareCustomers.MIMA, "3", "", "魅魔小姐竟然诞生源自那个雾雨家的魔法实验，真是太让人惊讶了！不过，就算有着这样的渊源，信念坚定的魅魔小姐也绝不会受任何人所有或支配。追求和探索真理是魅魔小姐一生的目标，就算因此和雾雨家决裂、打了上百年的仗也不曾改变过本心。");
        this.addCustomerDescriptionLevel(RareCustomers.MIMA, "5", "", "原来魅魔小姐就是魔理沙小姐的师傅！我早就应该想到的，她们俩真的有很多共同点！无论是追求知识的执著和专注这点，还是道德感方面…以及，从来不会展现自己软弱和脆弱的一面…表面看起来完全不同的，这两个孤独又坚定的人，过去会是什么样子的呢？");
        this.addCustomerDescriptionLevel(RareCustomers.LOUISE, "1", "", "经常偷偷溜出魔界甚至去外界旅行（工作）的魔界人，几乎随身带着一个可以自动行走的行李箱。工作内容是在一个叫做“博客”的地方分享自己的旅行过程，据说很受外面世界的人类欢迎。真奇怪，人类这么喜欢看别人旅行吗？");
        this.addCustomerDescriptionLevel(RareCustomers.LOUISE, "3", "", "原来露易兹小姐不仅仅分享旅行过程，也经常分享自己的创意设计。她不仅见多识广，有非常多有趣的想法和创意，还很了解时尚，很会夸人，很会做甜品…真希望自己也能成为像露易兹小姐这样优秀的人呀。");
        this.addCustomerDescriptionLevel(RareCustomers.LOUISE, "5", "", "就算像露易兹小姐这样满心满意地为了人类而行动的人，也一样无法得到所有人的认同。想要互相理解真不是一件容易的事啊。但就算这样，露易兹小姐也没有打算放弃热爱的工作。希望她的未来能够一直“不负热爱”。");
        this.addCustomerDescriptionLevel(RareCustomers.RINNOSUKE_MORICHIKA, "1", "", "自诩为普通的商人，买卖全凭兴趣，十分乱来。作为经营者前辈来说，应该是一个很好的反面教材吧？不过，偶尔也能淘到一些有用东西就是了。");
        this.addCustomerDescriptionLevel(RareCustomers.RINNOSUKE_MORICHIKA, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.RINNOSUKE_MORICHIKA, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.REMILIA_SCARLET, "1", "", "红魔馆的主人。远远看去还以为是个幼童，走近却被她的气势压得不敢说话，不愧是响彻一方的吸血鬼领主！但任性起来真的和小孩子很像…");
        this.addCustomerDescriptionLevel(RareCustomers.REMILIA_SCARLET, "3", "", "虽然她还不太成熟，但她背负着许多人的命运。明明是那么小小的肩膀，却把一大家子全都庇护在自己的羽翼下，还真有点儿一家之主的感觉。蕾米小姐，也不完全像大家认为的那样以自我为中心呢。");
        this.addCustomerDescriptionLevel(RareCustomers.REMILIA_SCARLET, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.YOUMU_KONPAKU, "1", "", "侍奉着冥界之主的庭师兼侍卫、厨师。也就是说，她不仅要一个人照顾两百由旬的西行寺庭院，还要守卫西行寺家以及主人的安危，同时还要照顾大胃王主人的饮食需求！无论哪一个都是重担呢，希望她能在夜雀食堂得到一些治愈吧！");
        this.addCustomerDescriptionLevel(RareCustomers.YOUMU_KONPAKU, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.YOUMU_KONPAKU, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.YUYUKO_SAIGYOUJI, "1", "", "差点儿吞噬了幻想乡的可怕的家伙。原以为恢复神志后就会世界和平，结果一见面就想吃了我？！现在偶尔也会到食堂用餐，有时候会看着我咽口水…我这辈子都不想再见到这个亡灵。");
        this.addCustomerDescriptionLevel(RareCustomers.YUYUKO_SAIGYOUJI, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.YUYUKO_SAIGYOUJI, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.MENG_CHENGGUO, "1", "", "MC幻想乡的板娘，通过“联动之门”穿越过来的异世界人，同时也担当驻夜雀食堂的形象大使，不断邀请着夜雀食堂世界的居民去MC幻想乡做客，积极的推进着两边的生态发展中。");
        this.addCustomerDescriptionLevel(RareCustomers.MENG_CHENGGUO, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.MENG_CHENGGUO, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.THREE_FAIRIES, "1", "", "蹦蹦跳跳的三妖精讨伐大作战中的主角，通过“联动之门”穿越过来的异世界妖精。因为无尽的好奇心和行动力，在本世界也受到了大家的欢迎，看到她们就感到元气满满。");
        this.addCustomerDescriptionLevel(RareCustomers.THREE_FAIRIES, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.THREE_FAIRIES, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.RIN_SATSUKI, "1", "", "在村子里的医馆担任护士的人类，性情直率纯粹，在医护的方面非常细心，对入院治愈后仍不爱惜自己身体的病人恨铁不成钢。面对这种病人，她会偷偷在下针的时候加大力度…");
        this.addCustomerDescriptionLevel(RareCustomers.RIN_SATSUKI, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.RIN_SATSUKI, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.SHIO_TACHISORA, "1", "", "来自八寒地狱的鬼卒，据说鬼卒的工作就是凌辱堕入地狱的罪人，好可怕！无论穿着打扮还是性格都是喧哗派，时常操着不像这个时代的混混的口头禅，好斗又好强，不是在打架，就是在找架打的路上。真怕她哪天会憋不住把我的店拆了…");
        this.addCustomerDescriptionLevel(RareCustomers.SHIO_TACHISORA, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.SHIO_TACHISORA, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.JIEN_YUU, "1", "", "新地狱的行政高官，八寒地狱鬼神长，似乎也是新地狱行政和司法方面的高级顾问。这样的大人物为什么会到我的店里来呢…难道我的店在地狱也有很名吗？");
        this.addCustomerDescriptionLevel(RareCustomers.JIEN_YUU, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.JIEN_YUU, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.HATA_NO_KOKORO, "1", "", "同时由六十六个面具组成的付丧神，平时基本上是不苟言笑的样子，偶尔眼神对上的话还会马上避开。一开始可能会觉得她性格冷淡，其实她只是习惯了依赖面具，所以无法理解情绪。某种程度来说，她就像婴儿一样单纯，实际上她在妖怪中也算是刚出生不久啦！现在她正在为了能够理解情绪而相当努力地修行着，相信她最后一定能露出属于自己的笑容！");
        this.addCustomerDescriptionLevel(RareCustomers.HATA_NO_KOKORO, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.HATA_NO_KOKORO, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.YUUMA_TOUTETSU, "1", "", "畜生界什么同盟的盟主，传说中的饕餮的动物灵，是个什么都能吸收的不得了的大胃王！性格会受吞下的事物的影响，如今似乎有了对美食的追求，偶尔会到店里来做客…体型和模样都像个小孩子，希望不会被哪个不怕死的妖怪给小瞧了吧…");
        this.addCustomerDescriptionLevel(RareCustomers.YUUMA_TOUTETSU, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.YUUMA_TOUTETSU, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.KOISHI_KOMEIJI, "1", "", "地灵殿之主的妹妹，封闭了第三只眼的觉！由于封闭了内心所以存在感也变得很低，神秘的身影让她在地底收获了许多追崇者。总是挂着灿烂的笑容，但谁也无法知道她真正的内心是怎么想的。就连她自己也不知道。");
        this.addCustomerDescriptionLevel(RareCustomers.KOISHI_KOMEIJI, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.KOISHI_KOMEIJI, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.MAMIZOU_FUTATSUIWA, "1", "", "妖怪狸的首领，有着相应的威严和领导风范，擅长变幻术。不过再如何擅长变幻的妖兽，想要完全藏起尾巴和耳朵都是不可能的。另外尾巴的大小其实是妖力的计量表，或许她从最初开始就没有藏起自己尾巴的打算。");
        this.addCustomerDescriptionLevel(RareCustomers.MAMIZOU_FUTATSUIWA, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.MAMIZOU_FUTATSUIWA, "5", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.YUKARI_YAKUMO, "1", "", "创造了幻想乡的贤者之一，据说是幻想乡最古老的妖怪，虽然神出鬼没而且性格有点儿不近人情，但其实一直以来暗中维护着幻想乡的安全和稳定…虽然没有得到多数人的理解，但恐怕也没有像她一样真挚地对待幻想乡、爱着幻想乡的人了。");
        this.addCustomerDescriptionLevel(RareCustomers.YUKARI_YAKUMO, "3", "", "");
        this.addCustomerDescriptionLevel(RareCustomers.YUKARI_YAKUMO, "5", "", "");


        // --- addCustomerChat ---
